import React from 'react';
import PizzaList from './components/PizzaList';
import styled from 'styled-components';

// Dados de exemplo para pizzas
const pizzas = [
  {
    id: 1,
    name: 'Margherita',
    description: 'Molho de tomate, mussarela, manjericão fresco.',
    price: 25.99,
    image: 'https://via.placeholder.com/300x200?text=Margherita',
  },
  {
    id: 2,
    name: 'Pepperoni',
    description: 'Molho de tomate, mussarela, pepperoni.',
    price: 29.99,
    image: 'https://via.placeholder.com/300x200?text=Pepperoni',
  },
  {
    id: 3,
    name: 'Quatro Queijos',
    description: 'Molho de tomate, mussarela, gorgonzola, parmesão, provolone.',
    price: 32.99,
    image: 'https://via.placeholder.com/300x200?text=Quatro+Queijos',
  },
];

function App() {
  return (
    <AppContainer>
      <Header>Efood - Pizzas</Header>
      <PizzaList pizzas={pizzas} />
    </AppContainer>
  );
}

export default App;

// Estilos
const AppContainer = styled.div`
  min-height: 100vh;
  background: #f5f5f5;
`;

const Header = styled.h1`
  text-align: center;
  padding: 20px;
  color: #333;
`;
